// ========== 工具函数 ==========

function pad(n) { return ("0" + n).slice(-2); }

function todayStr() {
  var d = new Date();
  return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-" + pad(d.getDate());
}

function todayDisplay() {
  var d = new Date();
  return d.getFullYear() + "年" + pad(d.getMonth() + 1) + "月" + pad(d.getDate()) + "日";
}

function getDaysInMonth() {
  var d = new Date();
  return new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
}

function getMonthStart() {
  var d = new Date();
  return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-01 00:00:00";
}

function getMonthEnd() {
  var d = new Date();
  var days = getDaysInMonth();
  return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-" + pad(days) + " 00:00:00";
}

function formatNow() {
  var d = new Date();
  return d.getFullYear() + "-" + pad(d.getMonth() + 1) + "-" + pad(d.getDate()) +
    " " + pad(d.getHours()) + ":" + pad(d.getMinutes()) + ":" + pad(d.getSeconds());
}

// 获取今天是今年的第几天（0-365）
function getDayOfYear() {
  var now = new Date();
  var start = new Date(now.getFullYear(), 0, 0);
  var diff = now - start;
  return Math.floor(diff / 86400000);
}

function delay(ms) {
  return new Promise(function(resolve) {
    setTimeout(resolve, ms);
  });
}

// 基础 HTTP 请求封装
function request(opts) {
  var fetchOpts = {
    url: opts.url,
    method: opts.method || "GET",
    headers: opts.headers || {},
    body: opts.body || undefined
  };
  if (opts.body && !opts.rawBody) {
    fetchOpts.headers["Content-Type"] = "application/json; charset=UTF-8";
  }
  return new Promise(function(resolve, reject) {
    $task.fetch(fetchOpts).then(
      function(resp) { resolve(resp); },
      function(err) { reject(err); }
    );
  });
}

// 构建公共请求头
function buildHeaders(isTask) {
  var h = {
    "User-Agent": UA,
    "Accept": "*/*",
    "Accept-Language": "zh-Hans-US;q=1, en-US;q=0.9",
    "os": "ios",
    "modelType": "0",
    "version": "4.1.8",
    "systemVersion": "18.7.7",
    "X-Access-Token": token,
    "customerCode": customerCode,
    "deviceToken": deviceToken,
    "Connection": "keep-alive"
  };
  if (cookie) { h["Cookie"] = cookie; }
  if (isTask) { h["referrerSource"] = encodeURIComponent("发现页"); }
  return h;
}

// 解析 JSON 响应
function parseResp(resp) {
  try { return JSON.parse(resp.body); }
  catch (e) {
    console.log("[GHAC] JSON 解析失败: " + resp.body.substring(0, 200));
    return null;
  }
}

// ========== 存储兼容层 ==========
var Store = {
  read: function(key) {
    if (typeof $persistentStore !== "undefined" && $persistentStore && $persistentStore.read) {
      return $persistentStore.read(key);
    }
    if (typeof $prefs !== "undefined" && $prefs && $prefs.valueForKey) {
      return $prefs.valueForKey(key);
    }
    return null;
  },
  write: function(val, key) {
    if (typeof $persistentStore !== "undefined" && $persistentStore && $persistentStore.write) {
      return $persistentStore.write(val, key);
    }
    if (typeof $prefs !== "undefined" && $prefs && $prefs.setValueForKey) {
      return $prefs.setValueForKey(val, key);
    }
    return false;
  }
};

